//! Launch Interceptor Program — Knight & Leveson (1986), per `spec.md`.
//! Reads one JSON object from stdin, writes one JSON object to stdout.
#![allow(non_snake_case)]

use serde::{Deserialize, Serialize};
use std::io::{self, Read, Write};

// --- realcompare_reference.rs (verbatim logic; do not alter) ---

pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

// --- end reference ---

const PI: f64 = 3.1415926535;

#[inline]
fn rc_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == LT
}

#[inline]
fn rc_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == GT
}

#[inline]
fn rc_eq(a: f64, b: f64) -> bool {
    realcompare(a, b) == EQ
}

#[inline]
fn rc_le(a: f64, b: f64) -> bool {
    !rc_gt(a, b)
}

#[inline]
fn rc_ge(a: f64, b: f64) -> bool {
    !rc_lt(a, b)
}

#[inline]
fn dist(ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    let dx = bx - ax;
    let dy = by - ay;
    (dx * dx + dy * dy).sqrt()
}

#[inline]
fn coincident(ax: f64, ay: f64, bx: f64, by: f64) -> bool {
    rc_eq(ax, bx) && rc_eq(ay, by)
}

/// Minimum enclosing circle radius for three planar points (MEC of a triangle / segment).
fn mec_radius_three(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    let d12 = dist(ax, ay, bx, by);
    let d23 = dist(bx, by, cx, cy);
    let d13 = dist(ax, ay, cx, cy);
    let mut s = [d12, d23, d13];
    s.sort_by(|u, v| {
        if rc_lt(*u, *v) {
            std::cmp::Ordering::Less
        } else if rc_gt(*u, *v) {
            std::cmp::Ordering::Greater
        } else {
            std::cmp::Ordering::Equal
        }
    });
    let a = s[0];
    let b = s[1];
    let c = s[2];
    let c_sq = c * c;
    let sum_sq = a * a + b * b;
    if rc_ge(c_sq, sum_sq) {
        return c * 0.5;
    }
    let p = (a + b + c) * 0.5;
    let area_sq = p * (p - a) * (p - b) * (p - c);
    if rc_le(area_sq, 0.0) {
        return c * 0.5;
    }
    let area = area_sq.sqrt();
    (a * b * c) / (4.0 * area)
}

fn cannot_fit_circle_r1(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64, r1: f64) -> bool {
    let mec = mec_radius_three(ax, ay, bx, by, cx, cy);
    rc_gt(mec, r1)
}

fn can_fit_circle_r2(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64, r2: f64) -> bool {
    let mec = mec_radius_three(ax, ay, bx, by, cx, cy);
    rc_le(mec, r2)
}

fn triangle_area(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    ((bx - ax) * (cy - ay) - (cx - ax) * (by - ay)).abs() * 0.5
}

fn quadrant(x: f64, y: f64) -> u8 {
    if rc_gt(x, 0.0) && rc_gt(y, 0.0) {
        return 1;
    }
    if rc_lt(x, 0.0) && rc_gt(y, 0.0) {
        return 2;
    }
    if rc_lt(x, 0.0) && rc_lt(y, 0.0) {
        return 3;
    }
    if rc_gt(x, 0.0) && rc_lt(y, 0.0) {
        return 4;
    }
    if rc_eq(x, 0.0) && rc_eq(y, 0.0) {
        return 1;
    }
    if rc_eq(x, 0.0) && rc_gt(y, 0.0) {
        return 1;
    }
    if rc_eq(x, 0.0) && rc_lt(y, 0.0) {
        return 3;
    }
    if rc_lt(x, 0.0) && rc_eq(y, 0.0) {
        return 2;
    }
    if rc_gt(x, 0.0) && rc_eq(y, 0.0) {
        return 1;
    }
    1
}

fn angle_at_vertex(ax: f64, ay: f64, vx: f64, vy: f64, bx: f64, by: f64) -> Option<f64> {
    if coincident(ax, ay, vx, vy) || coincident(bx, by, vx, vy) {
        return None;
    }
    let ux = ax - vx;
    let uy = ay - vy;
    let wx = bx - vx;
    let wy = by - vy;
    let nu = (ux * ux + uy * uy).sqrt();
    let nw = (wx * wx + wy * wy).sqrt();
    if rc_eq(nu, 0.0) || rc_eq(nw, 0.0) {
        return None;
    }
    let dot = ux * wx + uy * wy;
    let mut c = dot / (nu * nw);
    if rc_lt(c, -1.0) {
        c = -1.0;
    } else if rc_gt(c, 1.0) {
        c = 1.0;
    }
    Some(c.acos())
}

fn lic_angle_deviation(ax: f64, ay: f64, vx: f64, vy: f64, bx: f64, by: f64, epsilon: f64) -> bool {
    let Some(angle) = angle_at_vertex(ax, ay, vx, vy, bx, by) else {
        return false;
    };
    let low = PI - epsilon;
    let high = PI + epsilon;
    rc_lt(angle, low) || rc_gt(angle, high)
}

fn dist_point_to_infinite_line(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    if rc_eq(dx, 0.0) && rc_eq(dy, 0.0) {
        return dist(px, py, x1, y1);
    }
    let len_sq = dx * dx + dy * dy;
    let t = ((px - x1) * dx + (py - y1) * dy) / len_sq;
    let qx = x1 + t * dx;
    let qy = y1 + t * dy;
    dist(px, py, qx, qy)
}

#[derive(Debug, Deserialize)]
struct Parameters {
    LENGTH1: f64,
    RADIUS1: f64,
    EPSILON: f64,
    AREA1: f64,
    Q_PTS: usize,
    QUADS: usize,
    DIST: f64,
    N_PTS: usize,
    K_PTS: usize,
    A_PTS: usize,
    B_PTS: usize,
    C_PTS: usize,
    D_PTS: usize,
    E_PTS: usize,
    F_PTS: usize,
    G_PTS: usize,
    LENGTH2: f64,
    RADIUS2: f64,
    AREA2: f64,
}

#[derive(Debug, Deserialize)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

#[derive(Debug, Serialize)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

fn lcm_op(i: usize, j: usize, lcm: &[Vec<String>]) -> &'static str {
    let s = lcm[i][j].as_str();
    match s {
        "NOTUSED" => "NOTUSED",
        "ORR" => "ORR",
        "ANDD" => "ANDD",
        _ => "NOTUSED",
    }
}

fn decide(inp: &Input) -> Output {
    let n = inp.numpoints;
    let x = &inp.x;
    let y = &inp.y;
    let p = &inp.parameters;

    let mut cmv = vec![false; 15];

    // LIC 1
    for i in 0..n.saturating_sub(1) {
        if rc_gt(dist(x[i], y[i], x[i + 1], y[i + 1]), p.LENGTH1) {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..n.saturating_sub(2) {
        if cannot_fit_circle_r1(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], p.RADIUS1) {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..n.saturating_sub(2) {
        if lic_angle_deviation(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], p.EPSILON) {
            cmv[2] = true;
            break;
        }
    }

    // LIC 4
    for i in 0..n.saturating_sub(2) {
        let a = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if rc_gt(a, p.AREA1) {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    if p.Q_PTS <= n {
        for start in 0..=n.saturating_sub(p.Q_PTS) {
            let mut qs = [false; 5];
            for k in 0..p.Q_PTS {
                let q = quadrant(x[start + k], y[start + k]);
                qs[q as usize] = true;
            }
            let mut cnt = 0usize;
            for &b in &qs[1..=4] {
                if b {
                    cnt += 1;
                }
            }
            if cnt > p.QUADS {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6
    for i in 0..n.saturating_sub(1) {
        if rc_lt(x[i + 1], x[i]) {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 && p.N_PTS <= n {
        for start in 0..=n - p.N_PTS {
            let end = start + p.N_PTS - 1;
            let x1 = x[start];
            let y1 = y[start];
            let x2 = x[end];
            let y2 = y[end];
            let mut found = false;
            for k in start..=end {
                let d = if coincident(x1, y1, x2, y2) {
                    dist(x[k], y[k], x1, y1)
                } else {
                    dist_point_to_infinite_line(x[k], y[k], x1, y1, x2, y2)
                };
                if rc_gt(d, p.DIST) {
                    found = true;
                    break;
                }
            }
            if found {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8
    if n >= 3 {
        let gap = p.K_PTS + 1;
        for i in 0..n {
            let j = i + gap;
            if j < n && rc_gt(dist(x[i], y[i], x[j], y[j]), p.LENGTH1) {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        let span = p.A_PTS + p.B_PTS + 2;
        for i in 0..n {
            let j = i + p.A_PTS + 1;
            let k = i + span;
            if k < n
                && cannot_fit_circle_r1(x[i], y[i], x[j], y[j], x[k], y[k], p.RADIUS1)
            {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        let span = p.C_PTS + p.D_PTS + 2;
        for i in 0..n {
            let j = i + p.C_PTS + 1;
            let k = i + span;
            if k < n && lic_angle_deviation(x[i], y[i], x[j], y[j], x[k], y[k], p.EPSILON) {
                cmv[9] = true;
                break;
            }
        }
    }

    // LIC 11
    if n >= 5 {
        let span = p.E_PTS + p.F_PTS + 2;
        for i in 0..n {
            let j = i + p.E_PTS + 1;
            let k = i + span;
            if k < n {
                let a = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
                if rc_gt(a, p.AREA1) {
                    cmv[10] = true;
                    break;
                }
            }
        }
    }

    // LIC 12
    if n >= 3 {
        let gap = p.G_PTS + 1;
        for i in 0..n {
            let j = i + gap;
            if j < n && rc_lt(x[j], x[i]) {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 {
        let gap = p.K_PTS + 1;
        let mut far = false;
        let mut near = false;
        for i in 0..n {
            let j = i + gap;
            if j < n {
                let d = dist(x[i], y[i], x[j], y[j]);
                if rc_gt(d, p.LENGTH1) {
                    far = true;
                }
                if rc_lt(d, p.LENGTH2) {
                    near = true;
                }
            }
        }
        cmv[12] = far && near;
    }

    // LIC 14
    if n >= 5 {
        let span = p.A_PTS + p.B_PTS + 2;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n {
            let j = i + p.A_PTS + 1;
            let k = i + span;
            if k < n {
                if cannot_fit_circle_r1(x[i], y[i], x[j], y[j], x[k], y[k], p.RADIUS1) {
                    part1 = true;
                }
                if can_fit_circle_r2(x[i], y[i], x[j], y[j], x[k], y[k], p.RADIUS2) {
                    part2 = true;
                }
            }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15
    if n >= 5 {
        let span = p.E_PTS + p.F_PTS + 2;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n {
            let j = i + p.E_PTS + 1;
            let k = i + span;
            if k < n {
                let a = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
                if rc_gt(a, p.AREA1) {
                    part1 = true;
                }
                if rc_lt(a, p.AREA2) {
                    part2 = true;
                }
            }
        }
        cmv[14] = part1 && part2;
    }

    // PUM
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = inp.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            let cell = match lcm_op(i, j, &inp.lcm) {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => true,
            };
            pum[i][j] = cell;
        }
    }

    // FUV
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
            continue;
        }
        let mut all_true = true;
        for j in 0..15 {
            if !pum[i][j] {
                all_true = false;
                break;
            }
        }
        fuv[i] = all_true;
    }

    let launch = fuv.iter().all(|&v| v);

    Output {
        cmv,
        pum,
        fuv,
        launch,
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf)?;
    let inp: Input = serde_json::from_str(&buf)?;
    let out = decide(&inp);
    let s = serde_json::to_string(&out)?;
    io::stdout().write_all(s.as_bytes())?;
    Ok(())
}
